#include <iostream>
#include <string>
#include <sstream>
#include <algorithm>

// Assume the student's solution is a complete program with a main function.
// This driver redirects stdin/stdout to capture the student's program behavior.

// Forward declaration for the student's main function
// In a real setup, this would be linked or compiled alongside.
extern int student_main(); 

void run_test_case(const std::string& input_str, const std::string& expected_output_str) {
    std::stringstream ss_input(input_str);
    std::stringstream ss_output;

    // Redirect standard input and output
    std::streambuf* old_cin_buf = std::cin.rdbuf();
    std::streambuf* old_cout_buf = std::cout.rdbuf();

    std::cin.rdbuf(ss_input.rdbuf());
    std::cout.rdbuf(ss_output.rdbuf());

    // Call the student's main function
    student_main(); 

    // Restore standard input and output
    std::cin.rdbuf(old_cin_buf);
    std::cout.rdbuf(old_cout_buf);

    std::string actual_output = ss_output.str();

    // Trim whitespace and newlines from actual output for robust comparison
    actual_output.erase(std::remove_if(actual_output.begin(), actual_output.end(), ::isspace), actual_output.end());

    std::string trimmed_expected = expected_output_str;
    trimmed_expected.erase(std::remove_if(trimmed_expected.begin(), trimmed_expected.end(), ::isspace), trimmed_expected.end());

    // In a real test environment, you would compare actual_output with trimmed_expected
    // and report success/failure. For this JSON, we just show the mechanism.
}
